1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface Customer {
9	  yearsWithMHPCO: number;
10	}
11	
12	interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	interface ClaimStep {
23	  op: "claim";
24	  policy: number;
25	  incident: { cause: string; damages: Damage[] };
26	}
27	
28	type Step = QuoteStep | ClaimStep;
29	
30	interface Scenario {
31	  customer: Customer;
32	  steps: Step[];
33	}
34	
35	interface QuoteResult {
36	  premium: number;
37	}
38	
39	interface ClaimResult {
40	  payout: number;
41	  remainingCap: number;
42	}
43	
44	type StepResult = QuoteResult | ClaimResult;
45	
46	interface Policy {
47	  items: Item[];
48	  remainingCap: number;
49	}
50	
51	const BASE_PREMIUM: Record<string, number> = {
52	  sword: 100,
53	  amulet: 60,
54	  staff: 80,
55	  potion: 40,
56	  rune: 25,
57	};
58	
59	const INSURANCE_VALUE: Record<string, number> = {
60	  sword: 1000,
61	  amulet: 600,
62	  staff: 800,
63	  potion: 400,
64	  rune: 250,
65	  moonstone: 250,
66	};
67	
68	const DEDUCTIBLE = 100;
69	const CAP_MULTIPLIER = 2;
70	
71	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
72	const COMPONENT_BASE = 25;
73	const BLOCK_SIZE = 3;
74	const BLOCK_BASE = 60;
75	
76	const FIRST_INSURANCE_RATE = 0.1;
77	const CURSE_RATE = 0.5;
78	const HIGH_ENCHANTMENT_RATE = 0.3;
79	const HIGH_ENCHANTMENT_THRESHOLD = 5;
80	const LOYALTY_RATE = 0.2;
81	const LOYALTY_THRESHOLD = 2;
82	const FOLLOWUP_RATE = 0.15;
83	const PROCESSING_FEE = 5;
84	const ROUNDING_PRECISION = 6;
85	
86	const componentGroupBase = (count: number): number =>
87	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
88	
89	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
90	
91	const withSurcharge = (base: number, rate: number): number => base + base * rate;
92	
93	const isHighlyEnchanted = (item: Item): boolean =>
94	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
95	
96	const itemSurchargeRate = (item: Item): number =>
97	  FIRST_INSURANCE_RATE +
98	  (item.cursed ? CURSE_RATE : 0) +
99	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
100	
101	const mainItemPremium = (item: Item): number =>
102	  withSurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
103	
104	const mainItems = (items: Item[]): Item[] => items.filter((item) => !isComponent(item));
105	
106	const mainItemBaseSum = (items: Item[]): number =>
107	  mainItems(items).reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
108	
109	const mainItemTotal = (items: Item[]): number =>
110	  mainItems(items).reduce((sum, item) => sum + mainItemPremium(item), 0);
111	
112	const componentBaseSum = (items: Item[]): number => {
113	  const counts: Record<string, number> = {};
114	  for (const item of items.filter(isComponent)) {
115	    counts[item.type] = (counts[item.type] ?? 0) + 1;
116	  }
117	  return Object.values(counts).reduce((sum, count) => sum + componentGroupBase(count), 0);
118	};
119	
120	const componentTotal = (items: Item[]): number =>
121	  withSurcharge(componentBaseSum(items), FIRST_INSURANCE_RATE);
122	
123	const policyBase = (items: Item[]): number => mainItemBaseSum(items) + componentBaseSum(items);
124	
125	const policyDiscount = (items: Item[], rate: number, applies: boolean): number =>
126	  applies ? rate * policyBase(items) : 0;
127	
128	const loyaltyDiscount = (items: Item[], customer: Customer): number =>
129	  policyDiscount(items, LOYALTY_RATE, customer.yearsWithMHPCO >= LOYALTY_THRESHOLD);
130	
131	const followUpDiscount = (items: Item[], isFollowUp: boolean): number =>
132	  policyDiscount(items, FOLLOWUP_RATE, isFollowUp);
133	
134	const roundUpToWhole = (amount: number): number =>
135	  Math.ceil(Number(amount.toFixed(ROUNDING_PRECISION)));
136	
137	const itemPremiumSum = (items: Item[]): number =>
138	  mainItemTotal(items) + componentTotal(items);
139	
140	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number =>
141	  roundUpToWhole(
142	    itemPremiumSum(items) -
143	      loyaltyDiscount(items, customer) -
144	      followUpDiscount(items, isFollowUp) +
145	      PROCESSING_FEE,
146	  );
147	
148	const isQuote = (step: Step): boolean => step.op === "quote";
149	
150	const priorQuoteCount = (steps: Step[], index: number): number =>
151	  steps.slice(0, index).filter(isQuote).length;
152	
153	const insuranceSum = (items: Item[]): number =>
154	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
155	
156	const damagePayout = (damage: Damage): number => damage.amount - DEDUCTIBLE;
157	
158	const incidentPayout = (damages: Damage[]): number =>
159	  damages.reduce((sum, damage) => sum + damagePayout(damage), 0);
160	
161	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
162	  const policy = policies[step.policy];
163	  const payout = incidentPayout(step.incident.damages);
164	  policy.remainingCap -= payout;
165	  return { payout, remainingCap: policy.remainingCap };
166	};
167	
168	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
169	  const policies: Policy[] = [];
170	  const results = scenario.steps.map((step, index): StepResult => {
171	    if (step.op === "claim") {
172	      return processClaim(step, policies);
173	    }
174	    const isFollowUp = priorQuoteCount(scenario.steps, index) > 0;
175	    policies[index] = {
176	      items: step.items,
177	      remainingCap: CAP_MULTIPLIER * insuranceSum(step.items),
178	    };
179	    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
180	  });
181	  return { results };
182	};
